   141→    int64 old_slice_quota_out = _slice_quota_out;
   142→    int64 old_max_pending_buffer_size = _max_pending_buffer_size;
   143→    int64 old_keep_alive_ticks = _keep_alive_ticks;
   144→
   145→    _options.max_throughput_in = options.max_throughput_in;
   146→    _options.max_throughput_out = options.max_throughput_out;
   147→    _options.max_pending_buffer_size = options.max_pending_buffer_size;
   148→    _options.keep_alive_time = options.keep_alive_time;
   149→
   150→    _slice_quota_in = _options.max_throughput_in == -1 ?
   151→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
   152→    _slice_quota_out = _options.max_throughput_out == -1 ?
   153→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
   154→    _max_pending_buffer_size =
